func TestHeight(t *testing.T) {
	leaf := func() *Node { return &Node{} }

	tests := []struct {
		name string
		tree *Node
		want int
	}{
		{"empty", nil, 0},
		{"single", leaf(), 1},
		{"balanced depth 2", &Node{Left: leaf(), Right: leaf()}, 2},
		{"left-skewed depth 3", &Node{Left: &Node{Left: leaf()}}, 3},
		{"unbalanced takes max", &Node{
			Left:  leaf(),
			Right: &Node{Right: &Node{Right: leaf()}},
		}, 4},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := Height(tt.tree); got != tt.want {
				t.Errorf("Height() = %d, want %d", got, tt.want)
			}
		})
	}
}
```

The cases pin the recursion's base case (`nil -> 0`), a single node (`1`), and â€” most importantly â€” the `"unbalanced takes max"` case, which fails if someone wrote `l + r` or picked the wrong branch instead of `max(l, r) + 1`. Using a `leaf()` helper keeps the tree literals readable. For recursive functions, always include the empty/base case and at least one asymmetric input, since those expose the two most common bugs: a missing base case and combining sub-results incorrectly.

