// toSorted is a small helper to compare sets order-independently.
func toSorted(s Set[int]) []int {
	out := make([]int, 0, len(s))
	for k := range s {
		out = append(out, k)
	}
	sort.Ints(out)
	return out
}

func TestSetIntersect(t *testing.T) {
	tests := []struct {
		name string
		a, b Set[int]
		want []int
	}{
		{"overlap", NewSet(1, 2, 3, 4), NewSet(3, 4, 5), []int{3, 4}},
		{"disjoint", NewSet(1, 2), NewSet(3, 4), []int{}},
		{"identical", NewSet(1, 2), NewSet(1, 2), []int{1, 2}},
		{"empty operand", NewSet(1, 2), NewSet[int](), []int{}},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := toSorted(tt.a.Intersect(tt.b))
			if !slices.Equal(got, tt.want) {
				t.Errorf("Intersect = %v, want %v", got, tt.want)
			}
		})
	}
}
```

Because a set has no inherent order, the test converts the result to a sorted slice (`toSorted`) before comparing with `slices.Equal` â€” comparing sets directly by iteration order would be flaky. The cases pin the meaningful behaviors: partial overlap, fully disjoint sets (empty result), identical sets (result equals input), and intersection with an empty set (empty result). The disjoint and empty cases use `[]int{}` to assert the result has no elements.

