func TestColorString(t *testing.T) {
	tests := []struct {
		name string
		c    Color
		want string
	}{
		{"orange", Color{255, 128, 0}, "#FF8000"},
		{"black", Color{0, 0, 0}, "#000000"},
		{"white", Color{255, 255, 255}, "#FFFFFF"},
		{"needs padding", Color{1, 2, 3}, "#010203"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := tt.c.String(); got != tt.want {
				t.Errorf("Color%v.String() = %q, want %q", tt.c, got, tt.want)
			}
			// Also confirm fmt uses Stringer (so %v matches String()).
			if got := fmt.Sprintf("%v", tt.c); got != tt.want {
				t.Errorf("%%v of Color%v = %q, want %q", tt.c, got, tt.want)
			}
		})
	}
}
```

The "needs padding" and "black" cases are the important ones: they verify the `%02X` zero-padding, which is exactly where a hex formatter is most likely to be wrong (e.g. rendering `Color{1,2,3}` as `#123` instead of `#010203`). The second assertion checks that the type genuinely satisfies `fmt.Stringer`, so `%v`/`Println` route through `String()` â€” if someone accidentally gave it a pointer receiver, a `Color` value would stop formatting via `String` and this catches it.

